{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "Cliente - Escritório Jurídico",
  "description": "Entidade que representa um cliente do escritório de advocacia",
  "type": "object",
  "required": ["id", "nome", "cpf", "estado", "createdAt"],
  "properties": {
    "id": {
      "type": "string",
      "description": "UUID único do cliente",
      "pattern": "^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$"
    },
    "nome": {
      "type": "string",
      "description": "Nome completo do cliente",
      "minLength": 3,
      "maxLength": 255
    },
    "cpf": {
      "type": "string",
      "description": "CPF do cliente (formato: XXX.XXX.XXX-XX)",
      "pattern": "^\\d{3}\\.\\d{3}\\.\\d{3}-\\d{2}$"
    },
    "whatsapp": {
      "type": "string",
      "description": "Número WhatsApp (formato: +55 11 999999999)",
      "pattern": "^\\+55\\s?\\(?\\d{2}\\)?\\s?9\\d{4}-?\\d{4}$"
    },
    "email": {
      "type": "string",
      "format": "email",
      "description": "Email do cliente (opcional)"
    },
    "estado": {
      "type": "string",
      "description": "Estado de residência (UF)",
      "enum": ["SP", "MG", "RJ", "PR", "RS", "BA", "PE", "CE", "SC", "GO", "DF"]
    },
    "qualificacao": {
      "type": "string",
      "description": "Qualificação jurídica (profissão/condição)",
      "minLength": 3,
      "maxLength": 100
    },
    "renda_mensal": {
      "type": "number",
      "description": "Renda mensal aproximada (em reais)",
      "minimum": 0
    },
    "dependentes": {
      "type": "integer",
      "description": "Número de dependentes",
      "minimum": 0
    },
    "ativo": {
      "type": "boolean",
      "description": "Se cliente está ativo no sistema",
      "default": true
    },
    "createdAt": {
      "type": "string",
      "format": "date-time",
      "description": "Data de criação do cadastro"
    },
    "updatedAt": {
      "type": "string",
      "format": "date-time",
      "description": "Data da última atualização"
    },
    "processos": {
      "type": "array",
      "description": "IDs dos processos relacionados a este cliente",
      "items": {
        "type": "string",
        "pattern": "^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$"
      }
    },
    "notas": {
      "type": "string",
      "description": "Notas internas sobre o cliente",
      "maxLength": 1000
    }
  },
  "additionalProperties": false
}

