{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "Processo Jurídico",
  "description": "Entidade que representa um processo jurídico (ação de superendividamento, revisão de juros, etc)",
  "type": "object",
  "required": ["id", "clienteId", "tipo", "tribunal", "status", "createdAt"],
  "properties": {
    "id": {
      "type": "string",
      "description": "UUID único do processo",
      "pattern": "^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$"
    },
    "clienteId": {
      "type": "string",
      "description": "UUID do cliente responsável pelo processo",
      "pattern": "^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$"
    },
    "tipo": {
      "type": "string",
      "description": "Tipo de ação judicial",
      "enum": [
        "superendividamento",
        "revisao-juros",
        "busca-apreensao",
        "inventario",
        "separacao",
        "outro"
      ]
    },
    "tribunal": {
      "type": "string",
      "description": "Tribunal responsável (TJ de qual estado)",
      "enum": ["TJSP", "TJMG", "TJRJ", "TJPR", "TJRS", "TJBA", "TJPE", "TJCE", "TJSC", "TJGO", "TJDF"]
    },
    "vara": {
      "type": "string",
      "description": "Vara/Cartório específico (ex: '14ª Vara Cível')",
      "maxLength": 100
    },
    "numero_processo": {
      "type": "string",
      "description": "Número oficial do processo no tribunal (NNNNNNNDD/AAAA)",
      "pattern": "^\\d{7}\\d{2}/\\d{4}$"
    },
    "juiz": {
      "type": "string",
      "description": "Nome do juiz responsável",
      "maxLength": 255
    },
    "status": {
      "type": "string",
      "description": "Status atual do processo",
      "enum": [
        "diagnostico",
        "em-andamento",
        "em-recurso",
        "finalizado",
        "cancelado"
      ]
    },
    "teses": {
      "type": "array",
      "description": "Teses jurídicas aplicadas neste processo",
      "items": {
        "type": "string",
        "enum": [
          "impossibilidade-manifesta",
          "boa-fe",
          "minimo-existencial",
          "pratica-abusiva",
          "antecipacao-tutela",
          "limite-30-rendimentos",
          "falta-contraproposta"
        ]
      }
    },
    "prazos": {
      "type": "array",
      "description": "IDs dos prazos associados a este processo",
      "items": {
        "type": "string",
        "pattern": "^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$"
      }
    },
    "documentos": {
      "type": "array",
      "description": "Caminhos dos documentos/petições relacionadas",
      "items": {
        "type": "string"
      }
    },
    "valor_demanda": {
      "type": "number",
      "description": "Valor da demanda em reais (débito total)",
      "minimum": 0
    },
    "valor_proposto": {
      "type": "number",
      "description": "Valor proposto para repactuação",
      "minimum": 0
    },
    "andamentos": {
      "type": "array",
      "description": "Histórico de andamentos do processo",
      "items": {
        "type": "object",
        "properties": {
          "data": {
            "type": "string",
            "format": "date"
          },
          "descricao": {
            "type": "string"
          },
          "tipo": {
            "type": "string",
            "enum": ["peticio", "sentenca", "recurso", "intimacao", "outro"]
          }
        }
      }
    },
    "createdAt": {
      "type": "string",
      "format": "date-time",
      "description": "Data de criação do processo"
    },
    "updatedAt": {
      "type": "string",
      "format": "date-time",
      "description": "Data da última atualização"
    },
    "notas": {
      "type": "string",
      "description": "Notas internas sobre o processo",
      "maxLength": 2000
    }
  },
  "additionalProperties": false
}

