{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "Prazo Processual",
  "description": "Entidade que representa um prazo processual com alertas automáticos",
  "type": "object",
  "required": ["id", "processoId", "tipo", "dataBase", "diasLegais", "status"],
  "properties": {
    "id": {
      "type": "string",
      "description": "UUID único do prazo",
      "pattern": "^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$"
    },
    "processoId": {
      "type": "string",
      "description": "UUID do processo ao qual este prazo pertence",
      "pattern": "^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$"
    },
    "tipo": {
      "type": "string",
      "description": "Tipo de prazo processual",
      "enum": [
        "contestacao",
        "recurso",
        "agravo",
        "audiencia",
        "entrega-documentos",
        "resposta-intimacao",
        "comparecimento",
        "outro"
      ]
    },
    "descricao": {
      "type": "string",
      "description": "Descrição detalhada do prazo",
      "maxLength": 500
    },
    "dataBase": {
      "type": "string",
      "format": "date",
      "description": "Data de origem/base para cálculo (data da intimação ou decisão)"
    },
    "diasLegais": {
      "type": "integer",
      "description": "Quantidade de dias úteis (conforme Lei)",
      "minimum": 1,
      "maximum": 120
    },
    "dataVencimento": {
      "type": "string",
      "format": "date",
      "description": "Data calculada de vencimento do prazo (dias úteis + fins de semana/feriados)"
    },
    "status": {
      "type": "string",
      "description": "Status atual do prazo",
      "enum": [
        "pendente",
        "iniciado",
        "concluido",
        "atrasado",
        "cancelado"
      ]
    },
    "diasRestantes": {
      "type": "integer",
      "description": "Dias úteis restantes até o vencimento (calculado dinamicamente)",
      "minimum": -120
    },
    "lembrete": {
      "type": "object",
      "description": "Configuração de lembretes automáticos",
      "properties": {
        "ativado": {
          "type": "boolean",
          "default": true
        },
        "diasAntes": [
          {
            "type": "integer",
            "description": "Quantidade de dias antes para enviar alerta",
            "enum": [1, 3, 5, 7, 15]
          }
        ],
        "ultimoLembrete": {
          "type": "string",
          "format": "date-time",
          "description": "Data do último lembrete enviado"
        }
      }
    },
    "documentoBase": {
      "type": "string",
      "description": "Arquivo/documento que originou este prazo (referência para consulta)"
    },
    "createdAt": {
      "type": "string",
      "format": "date-time"
    },
    "updatedAt": {
      "type": "string",
      "format": "date-time"
    }
  },
  "additionalProperties": false
}

