  "proximos_passos": [
    "1. Gerar petição inicial com teses impossibilidade + boa-fé",
    "2. Injetar jurisprudência TJSP-001, STJ-001, STJ-002",
    "3. Revisar petição com @legal-chief antes de protocolar",
    "4. Calcular prazos (15 dias contestação, 30 dias audiência)",
    "5. Agendar configuração de alertas"
  ]
}
