---

## Algoritmo de Análise

### PASSO 1: Validação Básica

```javascript
function validarDados(cliente) {
  if (!cliente.renda_mensal || cliente.renda_mensal <= 0) {
    return { analisavel: false, motivo: "Renda inválida" };
  }
  if (!cliente.dividas || cliente.dividas.length === 0) {
    return { analisavel: false, motivo: "Nenhuma dívida informada" };
  }
  return { analisavel: true };
}
```

### PASSO 2: Cálculo de Impossibilidade Manifesta

```javascript
function calcularImpossibilidade(cliente) {
  const divida_total = cliente.dividas.reduce((sum, d) => sum + d.valor, 0);
  const proporcao = divida_total / cliente.renda_mensal;

  // Lei 14.181/2021: impossibilidade manifesta
  if (proporcao > 5) {
    return {
      superendividado: true,
      proporcao: proporcao,
      forca: "ALTA", // > 5x é inequívoco
      descricao: `Dívida é ${proporcao.toFixed(1)}x a renda mensal`
    };
  } else if (proporcao > 3) {
    return {
      superendividado: true,
      proporcao: proporcao,
      forca: "MEDIA",
      descricao: `Dívida é ${proporcao.toFixed(1)}x a renda mensal`
    };
  } else {
    return {
      superendividado: false,
      proporcao: proporcao,
      forca: "BAIXA",
      descricao: "Pode haver outras opções mais adequadas"
    };
  }
}
```

### PASSO 3: Validar Boa-Fé

```javascript
function validarBoaFe(cliente) {
  const boa_fe_score = 0;

  // Presunção de boa-fé (Lei 14.181)
  if (!cliente.tem_fraude) boa_fe_score += 1.0;
  else boa_fe_score -= 1.0;

  // Tentou negociar?
  if (cliente.tentou_negociar) boa_fe_score += 0.2;

  return {
    boa_fe: boa_fe_score >= 0.5,
    score: Math.max(0, Math.min(1, boa_fe_score)),
    observacao: boa_fe_score >= 0.5
      ? "Boa-fé presumida (ônus com credor)"
      : "Questão de boa-fé pode ser contestada"
  };
}
```

### PASSO 4: Selecionar Teses Aplicáveis

```javascript
function selecionarTeses(cliente, impossibilidade, boa_fe) {
  const teses = [];

  // Impossibilidade manifesta
  if (impossibilidade.superendividado && impossibilidade.forca === "ALTA") {
    teses.push("impossibilidade-manifesta");
  }

  // Boa-fé
  if (boa_fe.boa_fe) {
    teses.push("boa-fe");
  }

  // Mínimo existencial
  if (cliente.dependentes > 0 || impossibilidade.proporcao > 5) {
    teses.push("minimo-existencial");
  }

  // Antecipação de tutela (se há risco)
  if (impossibilidade.proporcao > 10) {
    teses.push("antecipacao-tutela");
  }

  return teses;
}
```

### PASSO 5: Consultar Jurisprudência

```javascript
function consultarJurisprudencia(teses, tribunal) {
  const jurisprudencia = {};

  for (const tese of teses) {
    // Buscar em: data/jurisprudencia/index.json
    // indices.por_tese[tese] → [decisões aplicáveis]
    jurisprudencia[tese] = buscarDecisoesPorTese(tese, tribunal);
  }

  return jurisprudencia;
}
```

### PASSO 6: Calcular Score de Aprovação

```javascript
function calcularScore(cliente, impossibilidade, boa_fe, tribunal_fav) {
  let score = 0;

  // Impossibilidade manifesta (peso 40%)
  if (impossibilidade.forca === "ALTA") score += 0.40;
  else if (impossibilidade.forca === "MEDIA") score += 0.25;

  // Boa-fé (peso 30%)
  if (boa_fe.boa_fe) score += 0.30;

  // Tribunal favorável (peso 20%)
  if (tribunal_fav.taxa_aprovacao > 0.70) score += 0.20;
  else if (tribunal_fav.taxa_aprovacao > 0.50) score += 0.10;

  // Mínimo existencial documentado (peso 10%)
  if (cliente.dependentes > 0) score += 0.10;

  return Math.min(1.0, score);
}
```

### PASSO 7: Montar Recomendação

```javascript
function montarRecomendacao(score, confianca, teses) {
  if (score >= 0.80 && teses.includes("impossibilidade-manifesta")) {
    return "PROSSEGUIR com ação de superendividamento (caso forte)";
  } else if (score >= 0.60) {
    return "PROSSEGUIR com ação, mas com análise jurídica aprofundada";
  } else if (score >= 0.40) {
    return "ANALISAR alternativas (revisar juros, busca-apreensão)";
  } else {
    return "NÃO RECOMENDADO - Cliente não atende critérios mínimos";
  }
}
```

