/**
 * Calculador de Prazos Processuais - Lei 14.181/2021 + CPC
 *
 * Calcula prazos processuais em dias úteis conforme:
 * - Lei 14.181/2021 (Superendividamento)
 * - CPC (Código de Processo Civil)
 * - Feriados federais e estaduais
 *
 * @author Legal Squad
 * @version 1.0
 */

class CalculadorPrazos {
  /**
   * Feriados Fixos (variam por tribunal)
   */
  static FERIADOS_FEDERAIS = [
    '0101', // Ano Novo
    '2104', // Tiradentes
    '0105', // Dia do Trabalho
    '0709', // Independência
    '1210', // Nossa Senhora Aparecida
    '0211', // Finados
    '1511', // Proclamação da República
    '2011', // Consciência Negra
    '2512'  // Natal
  ];

  /**
   * Feriados Estaduais por Tribunal
   */
  static FERIADOS_ESTADUAIS = {
    'TJSP': ['0907'], // Revolução Constitucionalista
    'TJMG': [],
    'TJRJ': ['2011'], // Consciência Negra
    'TJPR': [],
    'TJRS': []
  };

  /**
   * Tabela de Prazos por Lei
   */
  static PRAZOS_LEGAIS = {
    'contestacao': {
      dias: 15,
      lei: 'CPC 335',
      descricao: 'Prazo para contestação'
    },
    'recurso': {
      dias: 15,
      lei: 'CPC 1.009',
      descricao: 'Prazo para apelação'
    },
    'agravo': {
      dias: 15,
      lei: 'CPC 1.024',
      descricao: 'Prazo para agravo'
    },
    'resposta_intimacao': {
      dias: 10,
      lei: 'Lei 14.181',
      descricao: 'Resposta a intimação'
    },
    'entrega_documentos': {
      dias: 5,
      lei: 'Prática comum',
      descricao: 'Prazo para entregar documentos'
    },
    'audiencia': {
      dias: 0,
      lei: 'CPC 334',
      descricao: 'Data agendada (não tem prazo)'
    }
  };

  /**
   * Construtor
   */
  constructor() {
    this.timezone = 'America/Sao_Paulo';
  }

  /**
   * Verifica se data é fim de semana (sábado ou domingo)
   * @param {Date} data
   * @returns {boolean}
   */
  ehFimDeSemana(data) {
    const dia = data.getDay();
    return dia === 0 || dia === 6; // 0=domingo, 6=sábado
  }

  /**
   * Verifica se data é feriado federal ou estadual
   * @param {Date} data
   * @param {string} tribunal - TJSP, TJMG, etc
   * @returns {boolean}
   */
  ehFeriado(data, tribunal = 'TJSP') {
    // Formato: MMDD
    const mes = String(data.getMonth() + 1).padStart(2, '0');
    const dia = String(data.getDate()).padStart(2, '0');
    const chave = mes + dia;

    // Verificar feriado federal
    if (CalculadorPrazos.FERIADOS_FEDERAIS.includes(chave)) {
      return true;
    }

    // Verificar feriado estadual
    const feriadosEstadual = CalculadorPrazos.FERIADOS_ESTADUAIS[tribunal] || [];
    if (feriadosEstadual.includes(chave)) {
      return true;
    }

    // Moventes: Sexta-feira Santa, Corpus Christi
    // (Simplificado - em produção usar biblioteca como date-fns)
    const feriadosMoventes = this.calcularFeriadosMoventes(data.getFullYear());
    if (feriadosMoventes.some(f => f.getTime() === data.getTime())) {
      return true;
    }

    return false;
  }

  /**
   * Calcula feriados móveis (Sexta-feira Santa, Corpus Christi)
   * Fórmula de Computus para Páscoa
   * @param {number} ano
   * @returns {Date[]}
   */
  calcularFeriadosMoventes(ano) {
    // Páscoa (Computus)
    const a = ano % 19;
    const b = Math.floor(ano / 100);
    const c = ano % 100;
    const d = Math.floor(b / 4);
    const e = b % 4;
    const f = Math.floor((b + 8) / 25);
    const g = Math.floor((b - f + 1) / 3);
    const h = (19 * a + b - d - g + 15) % 30;
    const i = Math.floor(c / 4);
    const k = c % 4;
    const l = (32 + 2 * e + 2 * i - h - k) % 7;
    const m = Math.floor((a + 11 * h + 22 * l) / 451);
    const mes = Math.floor((h + l - 7 * m + 114) / 31);
    const dia = ((h + l - 7 * m + 114) % 31) + 1;

    const pascoa = new Date(ano, mes - 1, dia);

    // Sexta-feira Santa (2 dias antes de Páscoa)
    const sextaPauloSanta = new Date(pascoa);
    sextaPauloSanta.setDate(sextaPauloSanta.getDate() - 2);

    // Corpus Christi (60 dias depois de Páscoa)
    const corpusChristis = new Date(pascoa);
    corpusChristis.setDate(corpusChristis.getDate() + 60);

    return [sextaPauloSanta, corpusChristis];
  }

  /**
   * Conta dias úteis entre duas datas
   * @param {Date} dataInicio
   * @param {number} diasUteis - Quantidade de dias úteis a adicionar
   * @param {string} tribunal - TJSP, TJMG, etc
   * @returns {Date}
   */
  adicionarDiasUteis(dataInicio, diasUteis, tribunal = 'TJSP') {
    let data = new Date(dataInicio);
    let contador = 0;

    while (contador < diasUteis) {
      data.setDate(data.getDate() + 1);

      if (!this.ehFimDeSemana(data) && !this.ehFeriado(data, tribunal)) {
        contador++;
      }
    }

    // Se caiu em feriado/fds, pular para próximo dia útil
    while (this.ehFimDeSemana(data) || this.ehFeriado(data, tribunal)) {
      data.setDate(data.getDate() + 1);
    }

    return data;
  }

  /**
   * Formata data para YYYY-MM-DD
   * @param {Date} data
   * @returns {string}
   */
  formatarData(data) {
    const ano = data.getFullYear();
    const mes = String(data.getMonth() + 1).padStart(2, '0');
    const dia = String(data.getDate()).padStart(2, '0');
    return `${ano}-${mes}-${dia}`;
  }

  /**
   * Formata data para DD/MM/YYYY (brasileiro)
   * @param {Date} data
   * @returns {string}
   */
  formatarDataBR(data) {
    const dia = String(data.getDate()).padStart(2, '0');
    const mes = String(data.getMonth() + 1).padStart(2, '0');
    const ano = data.getFullYear();
    return `${dia}/${mes}/${ano}`;
  }

  /**
   * Calcula dias restantes até vencimento
   * @param {Date} dataVencimento
   * @returns {number} - Dias úteis restantes (negativo se atrasado)
   */
  diasRestantes(dataVencimento) {
    const hoje = new Date();
    hoje.setHours(0, 0, 0, 0);
    dataVencimento.setHours(0, 0, 0, 0);

    const diff = Math.floor((dataVencimento - hoje) / (1000 * 60 * 60 * 24));
    return diff;
  }

  /**
   * Calcula prazos para protocolo de ação
   * @param {string} dataProtocolo - YYYY-MM-DD
   * @param {string} tribunal - TJSP, TJMG, TJRJ, TJPR, TJRS
   * @returns {Object}
   */
  calcularPrazosProtocolo(dataProtocolo, tribunal = 'TJSP') {
    const data = new Date(dataProtocolo);

    const prazos = [
      {
        id: 'contestacao',
        tipo: 'contestacao',
        descricao: 'Prazo para contestação',
        dataBase: dataProtocolo,
        diasLegais: 15,
        dataVencimento: this.formatarData(
          this.adicionarDiasUteis(data, 15, tribunal)
        ),
        lei: 'CPC 335',
        status: 'pendente',
        lembrete: {
          ativado: true,
          diasAntes: [1, 3, 5, 7]
        }
      },
      {
        id: 'audiencia',
        tipo: 'audiencia',
        descricao: 'Audiência de conciliação',
        dataBase: dataProtocolo,
        diasLegais: 30,
        dataVencimento: this.formatarData(
          this.adicionarDiasUteis(data, 30, tribunal)
        ),
        lei: 'CPC 334 (estimado)',
        status: 'pendente',
        lembrete: {
          ativado: true,
          diasAntes: [1, 3, 5, 7]
        }
      },
      {
        id: 'entrega_documentos',
        tipo: 'entrega-documentos',
        descricao: 'Entrega de documentação (se necessário)',
        dataBase: dataProtocolo,
        diasLegais: 5,
        dataVencimento: this.formatarData(
          this.adicionarDiasUteis(data, 5, tribunal)
        ),
        lei: 'Prática comum',
        status: 'pendente',
        lembrete: {
          ativado: true,
          diasAntes: [1, 3]
        }
      }
    ];

    return {
      tribunal: tribunal,
      dataProtocolo: dataProtocolo,
      prazos: prazos,
      proximoVencimento: prazos[0].dataVencimento,
      resumo: `${prazos.length} prazos criados. Próximo: ${prazos[0].descricao} em ${prazos[0].dataVencimento}`
    };
  }

  /**
   * Calcula prazos após sentença
   * @param {string} dataSentenca - YYYY-MM-DD
   * @param {string} tribunal - TJSP, TJMG, etc
   * @returns {Object}
   */
  calcularPrazosRecurso(dataSentenca, tribunal = 'TJSP') {
    const data = new Date(dataSentenca);

    const prazos = [
      {
        id: 'recurso_apelacao',
        tipo: 'recurso',
        descricao: 'Prazo para recurso de apelação',
        dataBase: dataSentenca,
        diasLegais: 15,
        dataVencimento: this.formatarData(
          this.adicionarDiasUteis(data, 15, tribunal)
        ),
        lei: 'CPC 1.009',
        status: 'pendente',
        lembrete: {
          ativado: true,
          diasAntes: [1, 3, 5]
        }
      },
      {
        id: 'contrarrazoes',
        tipo: 'contrarrazoes',
        descricao: 'Prazo para contrarrazões (se houver recurso)',
        dataBase: dataSentenca,
        diasLegais: 30, // Estimado
        dataVencimento: this.formatarData(
          this.adicionarDiasUteis(data, 30, tribunal)
        ),
        lei: 'CPC 1.009 (estimado)',
        status: 'pendente',
        lembrete: {
          ativado: false
        }
      }
    ];

    return {
      tribunal: tribunal,
      dataSentenca: dataSentenca,
      prazos: prazos,
      proximoVencimento: prazos[0].dataVencimento,
      resumo: `Prazos de recurso. Apelação: ${prazos[0].dataVencimento}`
    };
  }

  /**
   * Calcula status de um prazo
   * @param {string} dataVencimento - YYYY-MM-DD
   * @param {boolean} cumprido
   * @returns {Object}
   */
  calcularStatusPrazo(dataVencimento, cumprido = false) {
    const dataVenc = new Date(dataVencimento);
    const hoje = new Date();
    hoje.setHours(0, 0, 0, 0);
    dataVenc.setHours(0, 0, 0, 0);

    const diasRestantes = Math.floor((dataVenc - hoje) / (1000 * 60 * 60 * 24));

    let status = 'pendente';
    let cor = 'verde'; // verde, amarelo, vermelho

    if (cumprido) {
      status = 'concluido';
      cor = 'verde';
    } else if (diasRestantes < 0) {
      status = 'atrasado';
      cor = 'vermelho';
    } else if (diasRestantes <= 3) {
      status = 'critico';
      cor = 'vermelho';
    } else if (diasRestantes <= 7) {
      status = 'alerta';
      cor = 'amarelo';
    }

    return {
      status: status,
      cor: cor,
      diasRestantes: diasRestantes,
      mensagem: this.gerarMensagem(status, diasRestantes)
    };
  }

  /**
   * Gera mensagem por status
   * @param {string} status
   * @param {number} dias
   * @returns {string}
   */
  gerarMensagem(status, dias) {
    const mensagens = {
      'pendente': `Prazo normal (${dias} dias)`,
      'alerta': `⚠️ Alerta: ${dias} dias para vencimento`,
      'critico': `🔴 CRÍTICO: ${Math.abs(dias)} dias para vencer`,
      'atrasado': `❌ ATRASADO em ${Math.abs(dias)} dias`,
      'concluido': '✅ Cumprido'
    };
    return mensagens[status] || 'Status desconhecido';
  }
}

/**
 * Exportar para uso em Node.js / módulos
 */
if (typeof module !== 'undefined' && module.exports) {
  module.exports = CalculadorPrazos;
}

/**
 * EXEMPLOS DE USO
 */
if (require.main === module) {
  console.log('\n========== CALCULADOR DE PRAZOS ==========\n');

  const calc = new CalculadorPrazos();

  // Exemplo 1: Protocolo de ação em 20/02/2026
  console.log('📅 EXEMPLO 1: Protocolo em 20/02/2026\n');
  const prazosProtocolo = calc.calcularPrazosProtocolo('2026-02-20', 'TJSP');
  console.log(`Tribunal: ${prazosProtocolo.tribunal}`);
  console.log(`Data Protocolo: ${prazosProtocolo.dataProtocolo}`);
  console.log(`\nPrazos calculados:`);
  prazosProtocolo.prazos.forEach(p => {
    console.log(`  • ${p.descricao}`);
    console.log(`    Data vencimento: ${calc.formatarDataBR(new Date(p.dataVencimento))}`);
    console.log(`    Lei: ${p.lei}`);
    console.log(`    Alertas: ${p.lembrete.diasAntes.join(', ')} dias antes\n`);
  });

  // Exemplo 2: Recurso após sentença
  console.log('\n📅 EXEMPLO 2: Sentença em 15/04/2026\n');
  const prazosRecurso = calc.calcularPrazosRecurso('2026-04-15', 'TJSP');
  console.log(`Tribunal: ${prazosRecurso.tribunal}`);
  console.log(`Data Sentença: ${prazosRecurso.dataSentenca}`);
  console.log(`\nPrazos para recurso:`);
  prazosRecurso.prazos.forEach(p => {
    console.log(`  • ${p.descricao}`);
    console.log(`    Vencimento: ${calc.formatarDataBR(new Date(p.dataVencimento))}`);
    console.log(`    Lei: ${p.lei}\n`);
  });

  // Exemplo 3: Status de um prazo
  console.log('\n⏳ EXEMPLO 3: Status atual de um prazo\n');
  const dataVenc = '2026-02-28';
  const status = calc.calcularStatusPrazo(dataVenc);
  console.log(`Data vencimento: ${calc.formatarDataBR(new Date(dataVenc))}`);
  console.log(`Status: ${status.status}`);
  console.log(`Dias restantes: ${status.diasRestantes}`);
  console.log(`Mensagem: ${status.mensagem}`);
}

