/**
 * Testes - Calculador de Prazos
 *
 * Execute com: node -r test.js calcular-prazos.test.js
 * Ou com Jest: npm test -- calcular-prazos.test.js
 */

const CalculadorPrazos = require('./calcular-prazos.js');

describe('CalculadorPrazos', () => {
  let calc;

  beforeEach(() => {
    calc = new CalculadorPrazos();
  });

  // ============= TESTES BÁSICOS =============

  describe('Identificação de dias úteis', () => {
    test('Deve identificar sábado corretamente', () => {
      // 15/02/2026 é sábado
      const sabado = new Date(2026, 1, 15);
      expect(calc.ehFimDeSemana(sabado)).toBe(true);
    });

    test('Deve identificar domingo corretamente', () => {
      // 16/02/2026 é domingo
      const domingo = new Date(2026, 1, 16);
      expect(calc.ehFimDeSemana(domingo)).toBe(true);
    });

    test('Deve identificar dia útil (segunda)', () => {
      // 17/02/2026 é segunda
      const segunda = new Date(2026, 1, 17);
      expect(calc.ehFimDeSemana(segunda)).toBe(false);
    });

    test('Deve identificar feriado (Ano Novo)', () => {
      const anoNovo = new Date(2026, 0, 1);
      expect(calc.ehFeriado(anoNovo, 'TJSP')).toBe(true);
    });

    test('Deve identificar feriado (Tiradentes)', () => {
      const tiradentes = new Date(2026, 3, 21); // 21/04
      expect(calc.ehFeriado(tiradentes, 'TJSP')).toBe(true);
    });

    test('Deve identificar dia útil normal', () => {
      // 18/02/2026 (quarta-feira, não feriado)
      const quarta = new Date(2026, 1, 18);
      expect(calc.ehFimDeSemana(quarta)).toBe(false);
      expect(calc.ehFeriado(quarta, 'TJSP')).toBe(false);
    });
  });

  // ============= TESTES DE CÁLCULO DE PRAZOS =============

  describe('Adicionar dias úteis', () => {
    test('Deve adicionar 15 dias úteis corretamente', () => {
      const dataInicio = new Date(2026, 1, 20); // 20/02/2026 (sexta)
      const dataFim = calc.adicionarDiasUteis(dataInicio, 15, 'TJSP');

      // Esperado: 10/03/2026 (terça)
      const esperado = new Date(2026, 2, 10);

      expect(calc.formatarData(dataFim)).toBe(calc.formatarData(esperado));
    });

    test('Deve pular fim de semana corretamente', () => {
      // 20/02/2026 é sexta
      // Próximo dia útil seria segunda 23/02
      const dataInicio = new Date(2026, 1, 20);
      const dataFim = calc.adicionarDiasUteis(dataInicio, 1, 'TJSP');

      const segunda = new Date(2026, 1, 23); // segunda-feira
      expect(calc.formatarData(dataFim)).toBe(calc.formatarData(segunda));
    });

    test('Deve pular feriado corretamente', () => {
      // 30/04/2026 é quinta
      // Dia 01/05 é feriado
      // Próximo dia útil seria 04/05
      const dataInicio = new Date(2026, 3, 30);
      const dataFim = calc.adicionarDiasUteis(dataInicio, 2, 'TJSP');

      const proximoDiaUtil = new Date(2026, 4, 4); // 04/05 (segunda)
      expect(calc.formatarData(dataFim)).toBe(calc.formatarData(proximoDiaUtil));
    });

    test('Deve adicionar 30 dias para audiência', () => {
      const dataInicio = new Date(2026, 1, 20); // 20/02
      const dataFim = calc.adicionarDiasUteis(dataInicio, 30, 'TJSP');

      // Esperado: 25/03/2026
      const esperado = new Date(2026, 2, 25);
      expect(calc.formatarData(dataFim)).toBe(calc.formatarData(esperado));
    });
  });

  // ============= TESTES DE PRAZOS PROCESSUAIS =============

  describe('Cálculo de prazos - Protocolo', () => {
    test('Deve gerar 3 prazos ao protocolar', () => {
      const resultado = calc.calcularPrazosProtocolo('2026-02-20', 'TJSP');
      expect(resultado.prazos.length).toBe(3);
    });

    test('Primeiro prazo deve ser contestação (15 dias)', () => {
      const resultado = calc.calcularPrazosProtocolo('2026-02-20', 'TJSP');
      expect(resultado.prazos[0].tipo).toBe('contestacao');
      expect(resultado.prazos[0].diasLegais).toBe(15);
    });

    test('Segundo prazo deve ser audiência (30 dias)', () => {
      const resultado = calc.calcularPrazosProtocolo('2026-02-20', 'TJSP');
      expect(resultado.prazos[1].tipo).toBe('audiencia');
      expect(resultado.prazos[1].diasLegais).toBe(30);
    });

    test('Terceiro prazo deve ser entrega de documentos (5 dias)', () => {
      const resultado = calc.calcularPrazosProtocolo('2026-02-20', 'TJSP');
      expect(resultado.prazos[2].tipo).toBe('entrega-documentos');
      expect(resultado.prazos[2].diasLegais).toBe(5);
    });

    test('Resultado deve incluir próximo vencimento', () => {
      const resultado = calc.calcularPrazosProtocolo('2026-02-20', 'TJSP');
      expect(resultado.proximoVencimento).toBeDefined();
      expect(resultado.proximoVencimento).toBe(resultado.prazos[0].dataVencimento);
    });

    test('Prazos devem ter alertas configurados', () => {
      const resultado = calc.calcularPrazosProtocolo('2026-02-20', 'TJSP');
      resultado.prazos.forEach(p => {
        expect(p.lembrete).toBeDefined();
        expect(p.lembrete.diasAntes).toBeDefined();
        expect(Array.isArray(p.lembrete.diasAntes)).toBe(true);
      });
    });
  });

  describe('Cálculo de prazos - Recurso', () => {
    test('Deve gerar 2 prazos ao recursar', () => {
      const resultado = calc.calcularPrazosRecurso('2026-04-15', 'TJSP');
      expect(resultado.prazos.length).toBe(2);
    });

    test('Primeiro prazo deve ser apelação (15 dias)', () => {
      const resultado = calc.calcularPrazosRecurso('2026-04-15', 'TJSP');
      expect(resultado.prazos[0].tipo).toBe('recurso');
      expect(resultado.prazos[0].diasLegais).toBe(15);
    });

    test('Resultado deve incluir data da sentença', () => {
      const resultado = calc.calcularPrazosRecurso('2026-04-15', 'TJSP');
      expect(resultado.dataSentenca).toBe('2026-04-15');
    });
  });

  // ============= TESTES DE STATUS =============

  describe('Status de prazos', () => {
    test('Prazo futuro deve ter status "pendente"', () => {
      const dataFutura = new Date();
      dataFutura.setDate(dataFutura.getDate() + 10);
      const status = calc.calcularStatusPrazo(calc.formatarData(dataFutura));
      expect(status.status).toBe('pendente');
    });

    test('Prazo de 1 dia deve ter status "critico"', () => {
      const dataAmanha = new Date();
      dataAmanha.setDate(dataAmanha.getDate() + 1);
      const status = calc.calcularStatusPrazo(calc.formatarData(dataAmanha));
      expect(status.status).toBe('critico');
    });

    test('Prazo atrasado deve ter status "atrasado"', () => {
      const dataOntem = new Date();
      dataOntem.setDate(dataOntem.getDate() - 1);
