      const segunda = new Date(2026, 1, 17);
      expect(calc.ehFimDeSemana(segunda)).toBe(false);
    });

    test('Deve identificar feriado (Ano Novo)', () => {
      const anoNovo = new Date(2026, 0, 1);
      expect(calc.ehFeriado(anoNovo, 'TJSP')).toBe(true);
