/**
 * Testes - Calculador de Prazos (Jest)
 *
 * Execute com: npm test -- calcular-prazos.spec.js
 */

import CalculadorPrazos from '../calcular-prazos.js';

describe('CalculadorPrazos - Testes Completos', () => {
  let calc;

  beforeEach(() => {
    calc = new CalculadorPrazos();
  });

  describe('Dias Úteis e Feriados', () => {
    test('Identifica sábado como fim de semana', () => {
      const sabado = new Date(2026, 1, 15); // 15/02/2026
      expect(calc.ehFimDeSemana(sabado)).toBe(true);
    });

    test('Identifica domingo como fim de semana', () => {
      const domingo = new Date(2026, 1, 16); // 16/02/2026
      expect(calc.ehFimDeSemana(domingo)).toBe(true);
    });

    test('Identifica segunda como dia útil', () => {
      const segunda = new Date(2026, 1, 17); // 17/02/2026 (segunda)
      expect(calc.ehFimDeSemana(segunda)).toBe(false);
    });

    test('Identifica Ano Novo como feriado', () => {
      const anoNovo = new Date(2026, 0, 1);
      expect(calc.ehFeriado(anoNovo, 'TJSP')).toBe(true);
    });

    test('Identifica Tiradentes como feriado', () => {
      const tiradentes = new Date(2026, 3, 21); // 21/04
      expect(calc.ehFeriado(tiradentes, 'TJSP')).toBe(true);
    });

    test('Identifica dia útil normal', () => {
      const quarta = new Date(2026, 1, 18); // 18/02/2026 (quarta)
      expect(calc.ehFimDeSemana(quarta)).toBe(false);
      expect(calc.ehFeriado(quarta, 'TJSP')).toBe(false);
    });

    test('TJSP reconhece feriado Revolução Constitucionalista', () => {
      const revolucao = new Date(2026, 6, 9); // 09/07
      expect(calc.ehFeriado(revolucao, 'TJSP')).toBe(true);
    });

    test('TJMG não reconhece feriado Revolução', () => {
      const revolucao = new Date(2026, 6, 9); // 09/07
      expect(calc.ehFeriado(revolucao, 'TJMG')).toBe(false);
    });
  });

  describe('Adição de Dias Úteis', () => {
    test('Adiciona 15 dias úteis corretamente', () => {
      const dataInicio = new Date(2026, 1, 20); // 20/02 (sexta)
      const dataFim = calc.adicionarDiasUteis(dataInicio, 15, 'TJSP');

      // Esperado: 10/03/2026 (terça)
      const esperado = new Date(2026, 2, 10);
      expect(calc.formatarData(dataFim)).toBe(calc.formatarData(esperado));
