      // Ambos devem ter prazos, mas TJSP pode ter datas diferentes por feriado
      expect(resultadoTJSP.prazos.length).toBe(3);
      expect(resultadoTJMG.prazos.length).toBe(3);
    });
  });

  describe('Integração com Lei 14.181/2021', () => {
    test('Respeita CPC 335 (contestação 15 dias)', () => {
      const resultado = calc.calcularPrazosProtocolo('2026-02-20', 'TJSP');
      expect(resultado.prazos[0].diasLegais).toBe(15);
      expect(resultado.prazos[0].lei).toBe('CPC 335');
    });

    test('Respeita CPC 334 (audiência ~30 dias)', () => {
      const resultado = calc.calcularPrazosProtocolo('2026-02-20', 'TJSP');
      expect(resultado.prazos[1].diasLegais).toBe(30);
    });

    test('Respeita CPC 1.009 (recurso 15 dias)', () => {
      const resultado = calc.calcularPrazosRecurso('2026-04-15', 'TJSP');
      expect(resultado.prazos[0].diasLegais).toBe(15);
      expect(resultado.prazos[0].lei).toBe('CPC 1.009');
    });
  });
});

