 */

describe('Legal Chief - Análise de Superendividamento', () => {
  /**
   * Implementação simplificada da análise para testes
   */
  class LegalChiefAnalyzer {
    analisarCliente(cliente) {
      // Validação básica
      if (!cliente.renda_mensal || cliente.renda_mensal <= 0) {
        return { analisavel: false, motivo: 'Renda inválida' };
      }
      if (!cliente.dividas || cliente.dividas.length === 0) {
        return { analisavel: false, motivo: 'Nenhuma dívida informada' };
      }

      // Cálculo de impossibilidade manifesta
      const divida_total = cliente.dividas.reduce((sum, d) => sum + d.valor, 0);
      const proporcao = divida_total / cliente.renda_mensal;

      let forca_impossibilidade = 'BAIXA';
      if (proporcao > 5) forca_impossibilidade = 'ALTA';
      else if (proporcao > 3) forca_impossibilidade = 'MEDIA';

      const superendividado = proporcao > 2.5;

      // Validar boa-fé
      const boa_fe_score = (!cliente.tem_fraude ? 1.0 : 0) +
                          (cliente.tentou_negociar ? 0.2 : 0);
      const boa_fe = boa_fe_score >= 0.5;

      // Selecionar teses
      const teses = [];
      if (superendividado && forca_impossibilidade === 'ALTA') {
        teses.push('impossibilidade-manifesta');
      }
      if (boa_fe) {
        teses.push('boa-fe');
      }
      if (cliente.dependentes > 0 || proporcao > 5) {
        teses.push('minimo-existencial');
      }
      if (proporcao > 10) {
        teses.push('antecipacao-tutela');
      }

      // Calcular score
      let score = 0;
      if (forca_impossibilidade === 'ALTA') score += 0.40;
      else if (forca_impossibilidade === 'MEDIA') score += 0.25;
      if (boa_fe) score += 0.30;
      if (cliente.tribunal_preferido === 'TJSP' && proporcao > 5) score += 0.20;
      if (cliente.dependentes > 0) score += 0.10;

      score = Math.min(1.0, score);

      // Recomendação
      let recomendacao = '';
      if (score >= 0.80 && teses.includes('impossibilidade-manifesta')) {
        recomendacao = 'PROSSEGUIR com ação de superendividamento (caso forte)';
      } else if (score >= 0.60) {
        recomendacao = 'PROSSEGUIR com ação (análise jurídica recomendada)';
      } else {
        recomendacao = 'NÃO RECOMENDADO';
      }

      return {
        analisavel: true,
        superendividado: superendividado,
        proporcao: proporcao,
        forca_impossibilidade: forca_impossibilidade,
        boa_fe: boa_fe,
        teses: teses,
        score_aprovacao: score,
        tribunal_recomendado: cliente.tribunal_preferido || 'TJSP',
        recomendacao: recomendacao,
        proximos_passos: [
          'Gerar petição inicial',
          'Revisar com advogado',
          'Protocolar em tribunal',
          'Monitorar prazos'
        ]
      };
    }
  }

  let legalChief;

  beforeEach(() => {
    legalChief = new LegalChiefAnalyzer();
  });

  describe('Validação de Dados', () => {
    test('Rejeita cliente sem renda', () => {
      const resultado = legalChief.analisarCliente({
        renda_mensal: 0,
        dividas: [{ valor: 10000 }]
      });
      expect(resultado.analisavel).toBe(false);
    });

    test('Rejeita cliente sem dívidas', () => {
      const resultado = legalChief.analisarCliente({
        renda_mensal: 2000,
        dividas: []
      });
      expect(resultado.analisavel).toBe(false);
    });

    test('Aceita cliente com dados válidos', () => {
      const resultado = legalChief.analisarCliente({
        renda_mensal: 2000,
        dividas: [{ valor: 50000 }],
        tribunal_preferido: 'TJSP',
        tem_fraude: false,
        tentou_negociar: true
      });
      expect(resultado.analisavel).toBe(true);
    });
  });

  describe('Classificação de Impossibilidade', () => {
    test('Detecta impossibilidade ALTA (> 5x renda)', () => {
      const resultado = legalChief.analisarCliente({
        renda_mensal: 2000,
        dividas: [{ valor: 116000 }],
        tribunal_preferido: 'TJSP',
        tem_fraude: false,
        tentou_negociar: true
      });
      expect(resultado.superendividado).toBe(true);
      expect(resultado.forca_impossibilidade).toBe('ALTA');
    });

    test('Detecta impossibilidade MEDIA (3-5x renda)', () => {
      const resultado = legalChief.analisarCliente({
        renda_mensal: 2000,
        dividas: [{ valor: 8000 }], // 4x
        tribunal_preferido: 'TJSP',
        tem_fraude: false,
        tentou_negociar: true
      });
      expect(resultado.superendividado).toBe(true);
      expect(resultado.forca_impossibilidade).toBe('MEDIA');
    });

    test('Rejeita impossibilidade BAIXA (< 2.5x)', () => {
      const resultado = legalChief.analisarCliente({
        renda_mensal: 2000,
        dividas: [{ valor: 4000 }], // 2x
        tribunal_preferido: 'TJSP',
        tem_fraude: false,
        tentou_negociar: true
      });
      expect(resultado.superendividado).toBe(false);
    });
  });

  describe('Validação de Boa-Fé', () => {
    test('Reconhece boa-fé sem fraude', () => {
      const resultado = legalChief.analisarCliente({
        renda_mensal: 2000,
        dividas: [{ valor: 50000 }],
        tribunal_preferido: 'TJSP',
        tem_fraude: false,
        tentou_negociar: true
      });
      expect(resultado.boa_fe).toBe(true);
    });

    test('Rejeita cliente com fraude', () => {
      const resultado = legalChief.analisarCliente({
        renda_mensal: 2000,
        dividas: [{ valor: 50000 }],
        tribunal_preferido: 'TJSP',
        tem_fraude: true,
        tentou_negociar: true
      });
      expect(resultado.boa_fe).toBe(false);
    });

    test('Reconhece tentativa de negociação', () => {
      const resultado = legalChief.analisarCliente({
        renda_mensal: 2000,
        dividas: [{ valor: 50000 }],
        tribunal_preferido: 'TJSP',
        tem_fraude: false,
        tentou_negociar: true
      });
      expect(resultado.boa_fe).toBe(true);
    });
  });

  describe('Seleção de Teses', () => {
    test('Seleciona impossibilidade-manifesta para caso forte', () => {
      const resultado = legalChief.analisarCliente({
        renda_mensal: 2000,
        dividas: [{ valor: 116000 }],
        tribunal_preferido: 'TJSP',
        tem_fraude: false,
        tentou_negociar: true
      });
      expect(resultado.teses).toContain('impossibilidade-manifesta');
    });

    test('Seleciona boa-fé quando aplicável', () => {
      const resultado = legalChief.analisarCliente({
        renda_mensal: 2000,
        dividas: [{ valor: 50000 }],
        tribunal_preferido: 'TJSP',
        tem_fraude: false,
        tentou_negociar: true
      });
      expect(resultado.teses).toContain('boa-fe');
    });

    test('Seleciona minimo-existencial com dependentes', () => {
      const resultado = legalChief.analisarCliente({
        renda_mensal: 2000,
        dividas: [{ valor: 50000 }],
        dependentes: 2,
        tribunal_preferido: 'TJSP',
        tem_fraude: false,
        tentou_negociar: true
      });
      expect(resultado.teses).toContain('minimo-existencial');
    });

    test('Seleciona antecipacao-tutela para casos extremos', () => {
      const resultado = legalChief.analisarCliente({
        renda_mensal: 1000,
        dividas: [{ valor: 116000 }], // 116x
        tribunal_preferido: 'TJSP',
        tem_fraude: false,
        tentou_negociar: true
      });
      expect(resultado.teses).toContain('antecipacao-tutela');
    });
  });

  describe('Score de Aprovação', () => {
    test('Caso forte (João Silva): score >= 0.80', () => {
      const resultado = legalChief.analisarCliente({
        renda_mensal: 2000,
        dividas: [
          { valor: 50000 },
          { valor: 35000 },
          { valor: 31000 }
        ],
        dependentes: 2,
        tribunal_preferido: 'TJSP',
        tem_fraude: false,
        tentou_negociar: true
      });
      expect(resultado.score_aprovacao).toBeGreaterThanOrEqual(0.80);
    });

    test('Caso médio: score 0.60-0.80', () => {
      const resultado = legalChief.analisarCliente({
        renda_mensal: 2000,
        dividas: [{ valor: 12000 }], // 6x
        tribunal_preferido: 'TJSP',
        tem_fraude: false,
        tentou_negociar: false
      });
      expect(resultado.score_aprovacao).toBeGreaterThanOrEqual(0.60);
    });

    test('Caso fraco: score < 0.60', () => {
      const resultado = legalChief.analisarCliente({
        renda_mensal: 2000,
        dividas: [{ valor: 4000 }], // 2x
        tribunal_preferido: 'TJSP',
        tem_fraude: false,
        tentou_negociar: false
      });
      expect(resultado.score_aprovacao).toBeLessThan(0.60);
    });

    test('Score não excede 1.0', () => {
      const resultado = legalChief.analisarCliente({
        renda_mensal: 2000,
        dividas: [{ valor: 200000 }], // extremamente alto
        dependentes: 5,
        tribunal_preferido: 'TJSP',
        tem_fraude: false,
        tentou_negociar: true
      });
      expect(resultado.score_aprovacao).toBeLessThanOrEqual(1.0);
    });
  });

  describe('Recomendações', () => {
    test('Recomenda PROSSEGUIR para caso forte', () => {
      const resultado = legalChief.analisarCliente({
        renda_mensal: 2000,
        dividas: [{ valor: 116000 }],
        tribunal_preferido: 'TJSP',
        tem_fraude: false,
        tentou_negociar: true
      });
      expect(resultado.recomendacao).toContain('PROSSEGUIR');
    });

    test('Recomenda NÃO RECOMENDADO para caso fraco', () => {
      const resultado = legalChief.analisarCliente({
        renda_mensal: 2000,
        dividas: [{ valor: 3000 }], // 1.5x
        tribunal_preferido: 'TJSP',
        tem_fraude: false,
        tentou_negociar: false
      });
      expect(resultado.recomendacao).toContain('NÃO RECOMENDADO');
    });

    test('Fornece próximos passos', () => {
      const resultado = legalChief.analisarCliente({
        renda_mensal: 2000,
        dividas: [{ valor: 50000 }],
        tribunal_preferido: 'TJSP',
        tem_fraude: false,
        tentou_negociar: true
      });
      expect(Array.isArray(resultado.proximos_passos)).toBe(true);
      expect(resultado.proximos_passos.length).toBeGreaterThan(0);
    });
  });

  describe('Casos Práticos', () => {
    test('João Silva: 58x renda → Caso forte', () => {
      const resultado = legalChief.analisarCliente({
        nome: 'João Silva',
        renda_mensal: 2000,
        dividas: [
          { credor: 'Itaú', valor: 50000 },
          { credor: 'Bradesco', valor: 35200 },
          { credor: 'BB', valor: 30800 }
        ],
        dependentes: 2,
        tribunal_preferido: 'TJSP',
        tem_fraude: false,
        tentou_negociar: true
      });

      expect(resultado.analisavel).toBe(true);
      expect(resultado.superendividado).toBe(true);
      expect(resultado.proporcao).toBeGreaterThan(50);
      expect(resultado.forca_impossibilidade).toBe('ALTA');
      expect(resultado.boa_fe).toBe(true);
      expect(resultado.score_aprovacao).toBeGreaterThanOrEqual(0.80);
      expect(resultado.recomendacao).toContain('PROSSEGUIR');
    });

    test('Cliente com dívida moderada → Possível', () => {
      const resultado = legalChief.analisarCliente({
        renda_mensal: 3000,
        dividas: [{ valor: 15000 }], // 5x
        dependentes: 1,
        tribunal_preferido: 'TJSP',
        tem_fraude: false,
        tentou_negociar: true
      });

      expect(resultado.analisavel).toBe(true);
      expect(resultado.superendividado).toBe(true);
      expect(resultado.score_aprovacao).toBeGreaterThan(0.50);
    });

    test('Cliente sem condições → Não recomendado', () => {
      const resultado = legalChief.analisarCliente({
        renda_mensal: 5000,
        dividas: [{ valor: 8000 }], // 1.6x
        tribunal_preferido: 'TJSP',
        tem_fraude: false,
        tentou_negociar: false
      });

      expect(resultado.analisavel).toBe(true);
      expect(resultado.superendividado).toBe(false);
      expect(resultado.recomendacao).toContain('NÃO RECOMENDADO');
    });
  });

  describe('Integração com Lei 14.181/2021', () => {
    test('Reconhece requisitos da Lei', () => {
      const resultado = legalChief.analisarCliente({
        renda_mensal: 2000,
        dividas: [{ valor: 116000 }],
        dependentes: 2,
        tribunal_preferido: 'TJSP',
        tem_fraude: false,
        tentou_negociar: true
      });

      // Lei 14.181: impossibilidade manifesta + boa-fé
      expect(resultado.teses).toContain('impossibilidade-manifesta');
      expect(resultado.boa_fe).toBe(true);
    });

    test('Calcula conforme Art. 54-A (impossibilidade + boa-fé)', () => {
      const resultado = legalChief.analisarCliente({
        renda_mensal: 2000,
        dividas: [{ valor: 50000 }],
        tribunal_preferido: 'TJSP',
        tem_fraude: false, // Requisito: boa-fé
        tentou_negociar: true
      });

      // Art. 54-A: impossibilidade manifesta + boa-fé
      expect(resultado.proporcao).toBeGreaterThan(2);
      expect(resultado.boa_fe).toBe(true);
    });
  });
});

